noncompliant:
#include <cstdio>

void test() {
  printf("%1$d", 1); // Noncompliant - positional arguments not in ISO C
  printf("%qd", (long long)1); // Noncompliant - 'q' length specifier not in ISO C
  printf("%zd", 1); // Noncompliant in older ISO C versions
}

compliant:
#include <cstdio>

void test() {
  printf("%d", 1); // Compliant - standard format specifier
  printf("%lld", (long long)1); // Compliant - ISO C standard for long long
  printf("%ld", (long)1); // Compliant - standard format
}
